import { test, expect } from "@playwright/test";

// ---------------------------------------------------------------------------
// Real e2e tests for GET /api/decode — no mocking, hits the running server.
// Assertions are written defensively: if the backend or OpenChain is
// unavailable we still verify the structural guarantees from our client-side
// decoder (outer func name, inner_calls count/selectors/names).
// ---------------------------------------------------------------------------

// 1. multicall((address,bytes,uint256,bool,bytes32)[])  — tuple_array
const TUPLE_ARRAY_DATA =
  "";

// 2. multicall(bytes[])  — bytes_array
const BYTES_ARRAY_DATA =
  "";

// 3. execute(bytes,bytes[])  — Universal Router, no deadline, commands=0x000d090f02
const UR_NO_DEADLINE_DATA =
  "";

// 4. execute(bytes,bytes[],uint256)  — Universal Router with deadline, commands=0x0b0004
const UR_WITH_DEADLINE_DATA =
  "";

// 5. Regular function — no multicall
const NORMAL_DATA =
  "0x3244c12c000000000000000000000000000000000000000000000000030d98d59a960000000000000000000000000000b98c948cfa24072e58935bc004a8a7b376ae746a";

test.describe("GET /api/decode", () => {
  test("multicall((address,bytes,uint256,bool,bytes32)[]) — 3 inner calls with named bundle fields", async ({
    request,
  }) => {
    const res = await request.get(`/api/decode?data=${TUPLE_ARRAY_DATA}`);
    expect(res.status()).toBe(200);
    const { data } = await res.json();
    const d0 = data[0];

    expect(d0.func).toBe("multicall((address,bytes,uint256,bool,bytes32)[])");
    expect(d0.args.bundle).toHaveLength(3);
    expect(d0.args.bundle[0].to).toMatch(/^0x/i);
    expect(d0.args.bundle[0].value).toBe("220000000000000000");

    expect(d0.inner_calls).toHaveLength(3);
    expect(d0.inner_calls[0].selector).toBeNull(); // ETH-only send, no calldata
    expect(d0.inner_calls[1].selector).toBe("0x3244c12c");
    expect(d0.inner_calls[2].selector).toBe("0x6ef5eeae");
    // inner calls may have .decoded if OpenChain resolves the selector
    if (d0.inner_calls[1].decoded) {
      expect(d0.inner_calls[1].decoded.func).toBe(
        "wrapNative(uint256,address)",
      );
    }
    if (d0.inner_calls[2].decoded) {
      expect(d0.inner_calls[2].decoded.func).toBe(
        "erc4626Deposit(address,uint256,uint256,address)",
      );
    }
  });

  test("multicall(bytes[]) — 2 inner calls, second is refundETH()", async ({
    request,
  }) => {
    const res = await request.get(`/api/decode?data=${BYTES_ARRAY_DATA}`);
    expect(res.status()).toBe(200);
    const { data } = await res.json();
    const d0 = data[0];

    expect(d0.func).toBe("multicall(bytes[])");
    expect(d0.inner_calls).toHaveLength(2);
    expect(d0.inner_calls[0].selector).toBe("0xdb3e2198");
    expect(d0.inner_calls[1].selector).toBe("0x12210e8a");
    if (d0.inner_calls[1].decoded) {
      expect(d0.inner_calls[1].decoded.func).toBe("refundETH()");
    }
  });

  test("execute(bytes,bytes[]) — Universal Router, 5 commands decoded by name", async ({
    request,
  }) => {
    const res = await request.get(`/api/decode?data=${UR_NO_DEADLINE_DATA}`);
    expect(res.status()).toBe(200);
    const { data } = await res.json();
    const d0 = data[0];

    expect(d0.func).toBe("execute(bytes,bytes[])");
    expect(d0.args.commands).toBe("0x000d090f02");
    expect(d0.inner_calls).toHaveLength(5);
    expect(d0.inner_calls[0].name).toBe("V3_SWAP_EXACT_IN");
    expect(d0.inner_calls[1].name).toBe("PERMIT2_TRANSFER_FROM_BATCH");
    expect(d0.inner_calls[2].name).toBe("V2_SWAP_EXACT_OUT");
    expect(d0.inner_calls[3].name).toBe("UNKNOWN_0x0f");
    expect(d0.inner_calls[4].name).toBe("PERMIT2_TRANSFER_FROM");
  });

  test("execute(bytes,bytes[],uint256) — Universal Router with deadline, 3 commands", async ({
    request,
  }) => {
    const res = await request.get(`/api/decode?data=${UR_WITH_DEADLINE_DATA}`);
    expect(res.status()).toBe(200);
    const { data } = await res.json();
    const d0 = data[0];

    expect(d0.func).toBe("execute(bytes,bytes[],uint256)");
    expect(d0.args.commands).toBe("0x0b0004");
    expect(d0.args.deadline).toBeDefined();
    expect(d0.inner_calls).toHaveLength(3);
    expect(d0.inner_calls[0].name).toBe("WRAP_ETH");
    expect(d0.inner_calls[1].name).toBe("V3_SWAP_EXACT_IN");
    expect(d0.inner_calls[2].name).toBe("SWEEP");
  });

  test("regular function call — no inner_calls", async ({ request }) => {
    const res = await request.get(`/api/decode?data=${NORMAL_DATA}`);
    expect(res.status()).toBe(200);
    const { data } = await res.json();
    const d0 = data[0];

    expect(d0.func).toBe("wrapNative(uint256,address)");
    expect(d0.args.arg0).toBe("220000000000000000");
    expect(d0.args.arg1).toMatch(/^0x/i);
    expect(d0.inner_calls).toBeUndefined();
  });
});
